def _stage38_legacy_item(
    item_id: str,
    name: str,
    category: str,
    affected: str,
    declared: Any,
    observed: Any,
    basis: str,
    limitation: str,
    limited: bool = False,
) -> dict[str, Any]:
    if observed in (None, "", "Not Available"):
        result = "Legacy Item Not Available"
    elif observed == declared:
        result = "Legacy Item Included With Limitation" if limited else "Legacy Item Included"
    else:
        result = "Legacy Gap Detected"
    return {
        "legacy_item_id": item_id,
        "item_name": name,
        "legacy_category": category,
        "affected_stage_or_output": affected,
        "declared_legacy_state": declared,
        "observed_legacy_state": observed,
        "legacy_result": result,
        "legacy_basis": basis,
        "limitation_statement": limitation,
    }


def build_framework_legacy_package(
    report_structure: dict[str, Any] | None = None,
    dependency_map: dict[str, Any] | None = None,
    stability_analysis: dict[str, Any] | None = None,
    transition_history: dict[str, Any] | None = None,
    output_provenance: dict[str, Any] | None = None,
    deterministic_replay: dict[str, Any] | None = None,
    integrity_verification: dict[str, Any] | None = None,
    audit_package: dict[str, Any] | None = None,
    conformance_certification: dict[str, Any] | None = None,
    reflexive_closure: dict[str, Any] | None = None,
    framework_continuity: dict[str, Any] | None = None,
    change_register: dict[str, Any] | None = None,
    governance_statement: dict[str, Any] | None = None,
    version_lineage: dict[str, Any] | None = None,
    lifecycle_review: dict[str, Any] | None = None,
    self_containment_certification: dict[str, Any] | None = None,
    stewardship_declaration: dict[str, Any] | None = None,
    declared_limitations: dict[str, Any] | None = None,
) -> dict[str, Any]:
    report = dict(report_structure or {})
    dependency = dict(dependency_map or {})
    stability = dict(stability_analysis or {})
    transitions = dict(transition_history or {})
    provenance = dict(output_provenance or {})
    replay = dict(deterministic_replay or {})
    integrity = dict(integrity_verification or {})
    audit = dict(audit_package or {})
    certification = dict(conformance_certification or {})
    closure = dict(reflexive_closure or {})
    continuity = dict(framework_continuity or {})
    register = dict(change_register or {})
    governance = dict(governance_statement or {})
    lineage = dict(version_lineage or {})
    lifecycle = dict(lifecycle_review or {})
    self_containment = dict(self_containment_certification or {})
    stewardship = dict(stewardship_declaration or {})
    summaries = {
        "replay": replay.get("replay_summary") or {},
        "integrity": integrity.get("integrity_summary") or {},
        "audit": audit.get("audit_package_summary") or {},
        "certification": certification.get("certification_summary") or {},
        "closure": closure.get("reflexive_closure_summary") or {},
        "continuity": continuity.get("continuity_summary") or {},
        "register": register.get("framework_change_register_summary") or {},
        "governance": governance.get("governance_summary") or {},
        "lineage": lineage.get("lineage_summary") or {},
        "lifecycle": lifecycle.get("lifecycle_summary") or {},
        "self_containment": self_containment.get("self_containment_summary") or {},
        "stewardship": stewardship.get("stewardship_summary") or {},
    }
    counts = {
        "dependency": len(dependency.get("nodes") or []),
        "pathway": len(stability.get("pathways") or []),
        "transition": len(transitions.get("transitions") or []),
        "provenance": len(provenance.get("provenance_entries") or []),
        "replay": len(replay.get("replay_entries") or []),
        "integrity": len(integrity.get("integrity_checks") or []),
        "audit": len(audit.get("audit_sections") or []),
        "certification": len(certification.get("certification_checks") or []),
        "closure": len(closure.get("closure_checks") or []),
        "continuity": len(continuity.get("continuity_checks") or []),
        "register": len(register.get("change_entries") or []),
        "governance": len(governance.get("governance_principles") or []),
        "lineage": len(lineage.get("version_lineage_entries") or []),
        "lifecycle": len(lifecycle.get("lifecycle_review_items") or []),
        "self_containment": len(self_containment.get("self_containment_checks") or []),
        "stewardship": len(stewardship.get("stewardship_declarations") or []),
        "lineage_relationships": len(lineage.get("lineage_relationships") or []),
    }
    limitation_sets = dict(declared_limitations or {
        "Stage 21": STAGE21_FULL_LIMITATIONS, "Stage 22": STAGE22_LIMITATIONS,
        "Stage 23": STAGE23_LIMITATIONS, "Stage 24": STAGE24_LIMITATIONS,
        "Stage 25": STAGE25_LIMITATIONS, "Stage 26": STAGE26_LIMITATIONS,
        "Stage 27": STAGE27_LIMITATIONS, "Stage 28": STAGE28_LIMITATIONS,
        "Stage 29": STAGE29_LIMITATIONS, "Stage 30": STAGE30_LIMITATIONS,
        "Stage 31": STAGE31_LIMITATIONS, "Stage 32": STAGE32_LIMITATIONS,
        "Stage 33": STAGE33_LIMITATIONS, "Stage 34": STAGE34_LIMITATIONS,
        "Stage 35": STAGE35_LIMITATIONS, "Stage 36": STAGE36_LIMITATIONS,
        "Stage 37": STAGE37_LIMITATIONS, "Stage 38": STAGE38_LIMITATIONS,
    })
    limitations_visible = bool(limitation_sets) and all(bool(tuple(value or ())) for value in limitation_sets.values())
    upstream_gaps = sum(int(value or 0) for value in (
        summaries["integrity"].get("integrity_gap_checks"), summaries["audit"].get("unavailable_sections"),
        summaries["certification"].get("non_conformance_checks"), summaries["closure"].get("closure_gap_count"),
        summaries["continuity"].get("continuity_gap_checks"), summaries["register"].get("change_gap_entries"),
        summaries["governance"].get("governance_gap_count"), summaries["lineage"].get("version_gap_count"),
        summaries["lifecycle"].get("lifecycle_gap_count"), summaries["self_containment"].get("self_containment_gap_count"),
        summaries["stewardship"].get("stewardship_gap_count"),
    ))
    replay_preserved = counts["replay"] == summaries["replay"].get("replayable_outputs") and summaries["replay"].get("non_replayable_outputs") == 0 if replay else None
    complete = True if stewardship else None
    specs = (
        ("LP-001", "Methodology Description", "Core Methodology", "CREF Methodology", True, complete, "The declared methodology remains visibly described.", "Description depends on preserved documentation."),
        ("LP-002", "Framework Purpose Statement", "Core Methodology", "Framework Purpose", True, complete, "The framework purpose remains visible.", "Purpose is descriptive only."),
        ("LP-003", "Scope Boundary Statement", "Core Methodology", "Framework Scope", True, complete, "Declared scope boundaries remain visible.", "Does not extend framework scope."),
        ("LP-004", "Limitation Set", "Boundary Package", "Stages 21–38 Limitations", True, limitations_visible, "Declared limitations remain available.", "Limitations do not validate external use."),
        ("LP-005", "Phase I Evaluation Methodology", "Phase Package", "Stages 1–19", True, complete, "Phase I remains declared in framework lineage.", "Does not rerun evaluation."),
        ("LP-006", "Phase II Reflexive Inspection Infrastructure", "Phase Package", "Stages 20–30", True, complete, "Phase II remains declared in framework lineage.", "Inspection outputs remain descriptive."),
        ("LP-007", "Phase III Methodology Governance", "Phase Package", "Stages 31–38", True, complete, "Implemented Phase III outputs remain visible.", "Stages 39–40 are not inferred."),
        ("LP-008", "Report Mode Structure", "Inspection Package", "Stage 21", 3, len(report.get("available_report_modes") or []) if report else None, "All report modes remain available.", "Full Inspection remains default."),
        ("LP-009", "Dependency Map", "Inspection Package", "Stage 22", 30, counts["dependency"] if dependency else None, "Dependency nodes remain preserved.", "Does not validate dependency truth."),
        ("LP-010", "Pathway Stability Record", "Inspection Package", "Stage 23", 8, counts["pathway"] if stability else None, "Pathways remain preserved.", "Does not predict outcomes."),
        ("LP-011", "Transition History Record", "Inspection Package", "Stage 24", 11, counts["transition"] if transitions else None, "Transition entries remain preserved.", "Does not infer prior states."),
        ("LP-012", "Output Provenance Record", "Inspection Package", "Stage 25", 14, counts["provenance"] if provenance else None, "Provenance entries remain preserved.", "Does not validate evidence."),
        ("LP-013", "Deterministic Replay Record", "Inspection Package", "Stage 26", True, replay_preserved, "Replay remains fully available.", "Does not simulate alternatives."),
        ("LP-014", "Framework Integrity Verification", "Verification Package", "Stage 27", (14, 0), (counts["integrity"], summaries["integrity"].get("integrity_gap_checks")) if integrity else None, "Integrity checks remain available without gaps.", "Structural integrity only."),
        ("LP-015", "Administrative Audit Package", "Verification Package", "Stage 28", (10, 0), (counts["audit"], summaries["audit"].get("unavailable_sections")) if audit else None, "Audit sections remain available.", "Not a legal audit."),
        ("LP-016", "Methodological Conformance Certification", "Verification Package", "Stage 29", (19, 0), (counts["certification"], summaries["certification"].get("non_conformance_checks")) if certification else None, "Conformance checks remain available.", "Not external certification."),
        ("LP-017", "Reflexive Closure Record", "Governance Package", "Stage 30", (23, 0), (counts["closure"], summaries["closure"].get("closure_gap_count")) if closure else None, "Reflexive closure remains preserved.", "Does not close the underlying case."),
        ("LP-018", "Framework Continuity Record", "Governance Package", "Stage 31", (23, 0), (counts["continuity"], summaries["continuity"].get("continuity_gap_checks")) if continuity else None, "Continuity remains preserved.", "Visible continuity only."),
        ("LP-019", "Framework Change Register", "Governance Package", "Stage 32", (25, 0), (counts["register"], summaries["register"].get("change_gap_entries")) if register else None, "Change entries remain preserved.", "Does not infer undocumented changes."),
        ("LP-020", "Framework Governance Statement", "Governance Package", "Stage 33", (25, 0), (counts["governance"], summaries["governance"].get("governance_gap_count")) if governance else None, "Governance principles remain preserved.", "Does not create authority."),
        ("LP-021", "Framework Version Lineage", "Governance Package", "Stage 34", (25, 0), (counts["lineage"], summaries["lineage"].get("version_gap_count")) if lineage else None, "Version lineage remains preserved.", "Does not infer undocumented versions."),
        ("LP-022", "Framework Lifecycle Review", "Governance Package", "Stage 35", (28, 0), (counts["lifecycle"], summaries["lifecycle"].get("lifecycle_gap_count")) if lifecycle else None, "Lifecycle review remains preserved.", "Does not infer future stages."),
        ("LP-023", "Framework Self-Containment Certification", "Portability Package", "Stage 36", (35, 0), (counts["self_containment"], summaries["self_containment"].get("self_containment_gap_count")) if self_containment else None, "Self-containment remains preserved.", "Does not certify software portability."),
        ("LP-024", "Framework Stewardship Declaration", "Preservation Package", "Stage 37", (25, 0), (counts["stewardship"], summaries["stewardship"].get("stewardship_gap_count")) if stewardship else None, "Stewardship declarations remain preserved.", "Does not create ownership."),
        ("LP-025", "Methodology / Implementation Separation Statement", "Portability Package", "Stages 36–38", True, complete, "CREF remains separable from its original implementation.", "Does not certify implementation correctness.", True),
        ("LP-026", "Independent Adoption Boundary", "Adoption Boundary", "Stage 38 Limitations", True, complete, "Adoption approval remains outside package scope.", "Does not approve institutional adoption.", True),
        ("LP-027", "Non-Software Dependency Declaration", "Portability Package", "CREF Methodology", True, complete, "Methodological understanding does not require a particular runtime.", "Documentation remains required.", True),
        ("LP-028", "Documentation Preservation Requirement", "Preservation Package", "Framework Documentation", True, limitations_visible, "Documentation is part of the preservation package.", "Availability depends on maintained artefacts."),
        ("LP-029", "Open Methodology Visibility", "Inspection Package", "Declared Methodology", True, complete, "Methodological boundaries remain visibly documented.", "Visibility does not guarantee perpetual publication.", True),
        ("LP-030", "Public Inspectability Record", "Inspection Package", "Stage 21 Report Modes", 3, len(report.get("available_report_modes") or []) if report else None, "Three inspection modes remain available.", "Admin rendering is not universal public access.", True),
        ("LP-031", "Future Stage Non-Inference Boundary", "Boundary Package", "Stages 39–40", "Undeclared and unimplemented", "Undeclared and unimplemented", "Future stages remain outside the package.", "Does not constrain future declared work."),
        ("LP-032", "Non-Mutation Boundary", "Boundary Package", "Stage 38 Limitations", True, any("does not modify records" in item.lower() for item in STAGE38_LIMITATIONS), "Packaging does not mutate records or outputs.", "Declarative boundary only."),
        ("LP-033", "Non-Authority Boundary", "Boundary Package", "Stage 38 Limitations", True, any("does not create institutional authority" in item.lower() for item in STAGE38_LIMITATIONS), "Packaging creates no institutional authority.", "Does not appoint a custodian."),
        ("LP-034", "Legacy Gap Absence", "Package Integrity", "Stages 27–37", 0, upstream_gaps if stewardship else None, "Visible upstream gap counts remain zero.", "No structural gap does not establish external validity."),
        ("LP-035", "Portable Methodology Package Declaration", "Portability Package", "Stage 38", True, complete, "Visible methodology artefacts are assembled for independent understanding and preservation.", "Does not certify software portability or adoption readiness.", True),
        ("LP-036", "Legacy Package Limitation Visibility", "Boundary Package", "Stage 38 Limitations", True, bool(STAGE38_LIMITATIONS), "Package limitations remain visible.", "Limitations govern every package item."),
    )
    items = [_stage38_legacy_item(*spec) for spec in specs]
    results = {name: sum(item["legacy_result"] == name for item in items) for name in (
        "Legacy Item Included", "Legacy Item Included With Limitation", "Legacy Item Not Available", "Legacy Gap Detected"
    )}
    if results["Legacy Gap Detected"]:
        state = "Framework Legacy Package Gap Detected"
    elif results["Legacy Item Not Available"]:
        state = "Framework Legacy Package Partially Available"
    elif results["Legacy Item Included With Limitation"]:
        state = "Framework Legacy Package Available With Limitations"
    else:
        state = "Framework Legacy Package Available"
    summary = {
        "legacy_package_state": state,
        "total_legacy_package_items": len(items),
        "included_legacy_items": results["Legacy Item Included"],
        "items_included_with_limitation": results["Legacy Item Included With Limitation"],
        "unavailable_legacy_items": results["Legacy Item Not Available"],
        "legacy_gap_count": results["Legacy Gap Detected"],
        "implemented_stage_count": 38, "declared_phase_count": 3,
        "version_lineage_relationship_count": counts["lineage_relationships"],
        "lifecycle_review_item_count": counts["lifecycle"],
        "self_containment_check_count": counts["self_containment"],
        "stewardship_declaration_count": counts["stewardship"],
        "dependency_node_count": counts["dependency"], "pathway_count": counts["pathway"],
        "transition_entry_count": counts["transition"], "provenance_entry_count": counts["provenance"],
        "replay_step_count": counts["replay"], "integrity_check_count": counts["integrity"],
        "audit_section_count": counts["audit"], "certification_check_count": counts["certification"],
        "reflexive_closure_check_count": counts["closure"], "continuity_check_count": counts["continuity"],
        "change_register_entry_count": counts["register"], "governance_principle_count": counts["governance"],
        "version_lineage_entry_count": counts["lineage"], "upstream_gap_count": upstream_gaps,
        "limitation_summary": "The package preserves visible methodology artefacts for understanding and continuation without certifying software portability, adoption, authority, or external validity.",
    }
    return {
        "legacy_package_state": state,
        "legacy_package_summary": summary,
        "legacy_package_items": items,
        "legacy_package_relationships": [
            {"relationship": name, "legacy_side": side, "declaration": declaration}
            for name, side, declaration in STAGE38_LEGACY_RELATIONSHIPS
        ],
        "limitations": list(STAGE38_LIMITATIONS),
    }


def _render_stage38_overview(package: dict[str, Any]) -> str:
    summary = package["legacy_package_summary"]
    labels = (
        ("Legacy Package State", "legacy_package_state"), ("Total Legacy Package Items", "total_legacy_package_items"),
        ("Included Legacy Items", "included_legacy_items"), ("Items Included With Limitation", "items_included_with_limitation"),
        ("Unavailable Legacy Items", "unavailable_legacy_items"), ("Legacy Gap Count", "legacy_gap_count"),
        ("Implemented Stage Count", "implemented_stage_count"), ("Declared Phase Count", "declared_phase_count"),
        ("Version Lineage Relationship Count", "version_lineage_relationship_count"), ("Lifecycle Review Item Count", "lifecycle_review_item_count"),
        ("Self-Containment Check Count", "self_containment_check_count"), ("Stewardship Declaration Count", "stewardship_declaration_count"),
        ("Dependency Node Count", "dependency_node_count"), ("Pathway Count", "pathway_count"),
        ("Transition Entry Count", "transition_entry_count"), ("Provenance Entry Count", "provenance_entry_count"),
        ("Replay Step Count", "replay_step_count"), ("Integrity Check Count", "integrity_check_count"),
        ("Audit Section Count", "audit_section_count"), ("Certification Check Count", "certification_check_count"),
        ("Reflexive Closure Check Count", "reflexive_closure_check_count"), ("Continuity Check Count", "continuity_check_count"),
        ("Change Register Entry Count", "change_register_entry_count"), ("Governance Principle Count", "governance_principle_count"),
        ("Version Lineage Entry Count", "version_lineage_entry_count"), ("Limitation Summary", "limitation_summary"),
    )
    return f'<section class="stage38-legacy-overview"><h3>Framework Legacy Package Overview</h3>{_render_stage18a_table(tuple((label, summary[key]) for label, key in labels))}</section>'


def _render_stage38_relationships(package: dict[str, Any]) -> str:
    rows = "".join(f"<tr><td>{escape(item['relationship'])}</td><td>{escape(item['legacy_side'])}</td><td>{escape(item['declaration'])}</td></tr>" for item in package["legacy_package_relationships"])
    return f'<section class="stage38-legacy-relationships"><h3>Legacy Package Relationships</h3><table><thead><tr><th>Relationship</th><th>Legacy Side</th><th>Declaration</th></tr></thead><tbody>{rows}</tbody></table></section>'


def _render_stage38_items(items: list[dict[str, Any]]) -> str:
    columns = (("Legacy Item ID", "legacy_item_id", True), ("Item Name", "item_name", False), ("Legacy Category", "legacy_category", False), ("Affected Stage or Output", "affected_stage_or_output", False), ("Declared Legacy State", "declared_legacy_state", False), ("Observed Legacy State", "observed_legacy_state", False), ("Legacy Result", "legacy_result", False), ("Legacy Basis", "legacy_basis", False), ("Limitation Statement", "limitation_statement", False))
    headers = "".join(f"<th>{escape(label)}</th>" for label, _, _ in columns)
    rows = "".join("<tr>" + "".join(f"<td><code>{escape(_stage18a_display_value(item.get(key)))}</code></td>" if code else f"<td>{escape(_stage18a_display_value(item.get(key)))}</td>" for _, key, code in columns) + "</tr>" for item in items)
    return f'<section class="stage38-full-legacy-items"><h3>Full Framework Legacy Package</h3><table><thead><tr>{headers}</tr></thead><tbody>{rows}</tbody></table></section>'


def _render_stage38_limitations(package: dict[str, Any], *, concise: bool = False) -> str:
    limitations = package["limitations"]
    if concise:
        limitations = [limitations[index] for index in (0, 2, 3, 7, 8, 9, 10, 11, 12, 13, 31, 32, 33)]
    return f'<section class="stage38-legacy-limitations"><h3>Framework Legacy Package Limitations</h3>{_render_stage19a_list(limitations, "No legacy package limitations available.")}</section>'


def _render_framework_legacy_package(package: dict[str, Any], *, report_mode: str) -> str:
    notice = '<p class="notice">Framework Legacy Package assembles visible methodology artefacts and declared metadata for independent understanding, preservation, and future continuation. It does not certify software portability, implementation correctness, legal validity, authority, or external adoption.</p>'
    overview = _render_stage38_overview(package)
    relationships = _render_stage38_relationships(package)
    if report_mode == "executive":
        content, mode_class = overview + _render_stage38_limitations(package, concise=True), "stage38-legacy-executive"
    elif report_mode == "review":
        content, mode_class = overview + relationships + _render_stage38_limitations(package), "stage38-legacy-review"
    else:
        content, mode_class = overview + relationships + _render_stage38_items(package["legacy_package_items"]) + _render_stage38_limitations(package), "stage38-legacy-full"
    return f'<section class="management-section stage38-framework-legacy-package {mode_class}"><h2>Framework Legacy Package</h2>{notice}{content}</section>'


