def _request_prefers_html(request: Request) -> bool:
    headers = getattr(request, "headers", {}) or {}
    try:
        accept = str(headers.get("accept") or headers.get("Accept") or "")
    except AttributeError:
        accept = ""
    return "text/html" in accept.casefold()


def _render_duplicate_intake_panel(
    detail: Mapping[str, Any],
    *,
    admin_session: Mapping[str, Any] | None = None,
) -> str:
    existing = detail.get("existing_document") if isinstance(detail.get("existing_document"), Mapping) else {}
    title = str(existing.get("title") or "Untitled document")
    document_identifier = str(existing.get("document_identifier") or "Not assigned")
    optional_reference = str(existing.get("reference_identifier") or "Not provided")
    lifecycle_label = str(existing.get("lifecycle_label") or "Unknown")
    duplicate_reason = str(detail.get("duplicate_reason") or "document identity")
    duplicate_reason_label = "SHA-256" if duplicate_reason == "sha256" else duplicate_reason
    admin_url = str(detail.get("admin_url") or "")
    action_label = str(detail.get("action_label") or "Open existing intake record")
    action = (
        f'<p><a class="duplicate-action" href="{escape(admin_url)}">{escape(action_label)}</a></p>'
        if admin_url.startswith("/admin/document-intake/")
        else ""
    )
    return f"""<!DOCTYPE html><html lang="en"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"><title>Duplicate Document Intake</title><style>*{{box-sizing:border-box}}body{{margin:0;background:#f4f3ef;color:#222;font-family:system-ui,sans-serif}}main{{width:min(920px,calc(100% - 32px));margin:32px auto 64px}}h1,h2{{color:#143a52}}a{{color:#245d61}}.admin-console-navigation{{display:flex;flex-wrap:wrap;gap:8px 18px;padding:12px 0;border-bottom:1px solid #d8d4ca;margin-bottom:24px}}.admin-console-navigation a{{font-weight:650}}.duplicate-panel{{padding:18px;border:1px solid #d8d4ca;border-left:5px solid #8a6d1f;background:#fff}}dl{{display:grid;grid-template-columns:170px minmax(0,1fr);gap:8px 14px}}dt{{font-weight:700;color:#555}}dd{{margin:0;overflow-wrap:anywhere}}.duplicate-action{{display:inline-block;padding:10px 14px;background:#245d61;color:#fff;text-decoration:none}}.notice{{padding:12px 14px;border-left:4px solid #2e8b9a;background:#fff}}@media(max-width:640px){{dl{{grid-template-columns:1fr}}.duplicate-action{{width:100%;text-align:center}}}}</style></head><body><main>{_render_admin_console_navigation(admin_session=admin_session)}<h1>Duplicate document detected</h1><section class="duplicate-panel" role="alert" aria-labelledby="duplicate-document-heading" tabindex="-1"><h2 id="duplicate-document-heading">Duplicate document detected</h2><p>{escape(str(detail.get("message") or "This document already exists."))}</p><dl><dt>Existing title</dt><dd>{escape(title)}</dd><dt>Document Identifier</dt><dd>{escape(document_identifier)}</dd><dt>Optional Reference Identifier</dt><dd>{escape(optional_reference)}</dd><dt>State</dt><dd>{escape(lifecycle_label)}</dd><dt>Matched by</dt><dd>{escape(duplicate_reason_label)}</dd></dl><p><strong>Recommended action:</strong> {escape(str(detail.get("recommended_action") or "Review the existing intake record before continuing."))}</p>{action}</section><p class="notice">Duplicate intake remains blocked. No new document intake record was created, and the existing document lifecycle was not changed.</p><p><a href="/admin/document-intake#new-intake">Back to Admin Document Intake</a></p></main></body></html>"""


@router.post("/api/admin/session/document-intake", response_class=HTMLResponse)
def admin_document_intake_upload(
    request: Request,
    title: str = Form(...),
    institution_source: str = Form(...),
    document_date: str = Form(...),
    category: str = Form(...),
    description: str = Form(...),
    visibility: str = Form(...),
    notes: str = Form(...),
    reference_identifier: str | None = Form(None),
    keywords: str | None = Form(None),
    file: UploadFile = File(...),
):
    session = require_admin_session(request)
    data = _read_uploaded_file(file)
    try:
        item = store_pending_document(
            data=data,
            original_filename=getattr(file, "filename", None) or "document.pdf",
            content_type=getattr(file, "content_type", None),
            title=title,
            institution_source=institution_source,
            document_date=document_date,
            category=category,
            description=description,
            visibility=visibility,
            notes=notes,
            reference_identifier=reference_identifier,
            keywords=keywords,
            actor=_admin_session_actor(session),
            root=intake_root(),
        )
    except ValueError as exc:
        detail = str(exc)
        status_code = {
            "document_intake_file_type_not_allowed": 415,
            "document_intake_file_too_large": 413,
            "document_intake_duplicate": 409,
        }.get(detail, 400)
        if detail == "document_intake_duplicate":
            response_detail = document_intake_duplicate_detail(data, root=intake_root())
            if _request_prefers_html(request):
                return HTMLResponse(
                    content=_render_duplicate_intake_panel(response_detail, admin_session=session),
                    status_code=409,
                )
        else:
            response_detail = document_intake_upload_error_detail(
                detail,
                data=data,
                original_filename=getattr(file, "filename", None) or "document.pdf",
                content_type=getattr(file, "content_type", None),
            )
        raise _http_error(status_code, response_detail) from exc
    return HTMLResponse(
        content=_render_document_intake_preview(item, admin_session=session),
        status_code=201,
    )


@router.post(
    "/api/admin/session/document-intake/{intake_id}/canonical-record",
    response_class=HTMLResponse,
)
def admin_canonical_record_from_document_create(
    intake_id: str,
    request: Request,
    record_type: str = Form(...),
    reference: str = Form(...),
    record_title: str = Form(...),
    institution: str = Form(...),
    event_date: str = Form(...),
    summary: str = Form(...),
    trajectory: str = Form(...),
    system_state: str = Form(...),
    conditions: str | None = Form(None),
    signals: str | None = Form(None),
    source_narrative: str = Form(...),
    create_association: str | None = Form(None),
    association_public_label: str | None = Form(None),
    association_public_note: str | None = Form(None),
):
    session = require_admin_session(request)
    actor = _admin_session_actor(session)
    try:
        item = load_pending_document(intake_id)
    except ValueError as exc:
        raise _http_error(404, "document_intake_not_found") from exc
    if str(item.get("status") or "").lower() != "published":
        raise _http_error(400, "source_document_not_published")

    normalized_reference = str(reference or "").strip()
    if not normalized_reference:
        raise _http_error(400, "record_reference_required")

    conn = get_db()
    try:
        record_routes.ensure_record_metadata_columns(conn)
        existing = conn.execute(
            "SELECT 1 FROM records WHERE reference = ? LIMIT 1",
            (normalized_reference,),
        ).fetchone()
        if existing:
            raise _http_error(409, "record_reference_already_exists")
    finally:
        conn.close()

    provenance = "\n".join(
        part
        for part in (
            str(source_narrative or "").strip(),
            f"Created from Published document: {item.get('document_identifier') or item.get('intake_id')}",
            f"Source document intake ID: {item.get('intake_id')}",
            f"Source document SHA-256: {item.get('sha256_hash')}",
            f"Canonical record creation initiated from Published document by {actor}.",
            f"Canonical record created from Published document by {actor}.",
        )
        if part
    )
    generated_at = (
        str(event_date or "").strip() + "T00:00:00Z"
        if re.match(r"^\d{4}-\d{2}-\d{2}$", str(event_date or "").strip())
        else datetime.now(timezone.utc).isoformat()
    )
    payload = SimpleNamespace(
        reference=normalized_reference,
        record_type=str(record_type or "strike").strip(),
        record_title=str(record_title or "").strip(),
        institution=str(institution or "").strip(),
        event_date=str(event_date or "").strip(),
        summary=str(summary or "").strip(),
        source_document_id=str(item.get("intake_id") or ""),
        source_document_reference=str(item.get("reference_identifier") or ""),
        generated_at=generated_at,
        trajectory=str(trajectory or "").strip(),
        system_state=str(system_state or "").strip(),
        conditions=_split_terms(conditions),
        signals=_split_terms(signals),
        finding=str(summary or "").strip(),
        report={
            "record_title": str(record_title or "").strip(),
            "institution": str(institution or "").strip(),
            "event_date": str(event_date or "").strip(),
            "source_document_reference": str(item.get("reference_identifier") or ""),
        },
        language="en",
        supersedes=None,
        source_narrative=provenance,
    )

    try:
        record_routes.create_record_entry(payload)
    except HTTPException:
        raise
    except ValueError as exc:
        raise _http_error(400, str(exc)) from exc

    association_notice = ""
    if str(create_association or "").strip() == "1":
        conn = get_db()
        try:
            association = rda.create_association(
                conn,
                record_reference=normalized_reference,
                document_id=str(item.get("intake_id") or ""),
                relationship_type="supporting_document",
                public_label=association_public_label or "Supporting document",
                public_note=association_public_note or "",
                admin_note="Created during canonical-record-from-document workflow.",
                is_public="1",
                actor=actor,
                root=intake_root(),
            )
            association_notice = (
                f'<p class="notice">Source document association created: '
                f'{escape(str(association.get("public_reference") or ""))}</p>'
            )
        except ValueError as exc:
            raise _http_error(409, str(exc)) from exc
        finally:
            conn.close()

    page = (
        '<!DOCTYPE html><html lang="en"><head><meta charset="UTF-8"><title>Canonical record created</title>'
        '<style>body{font-family:system-ui,sans-serif;background:#f4f3ef;color:#222}main{width:min(900px,calc(100% - 32px));margin:32px auto}.notice{padding:14px 16px;border-left:4px solid #2e8b9a;background:#fff}a{color:#245d61}</style></head>'
        f'<body><main>{_render_admin_console_navigation(admin_session=session)}<h1>Canonical record created</h1>'
        f'<p class="notice">Created canonical record <strong>{escape(normalized_reference)}</strong> from Published document context. The source document remains unchanged.</p>'
        f'{association_notice}<p><a href="/verify/{escape(normalized_reference)}">View canonical record</a> · '
        f'<a href="/admin/document-intake/{escape(intake_id)}">Return to source document</a> · '
        '<a href="/admin/associations/new">Create association</a></p></main></body></html>'
    )
    return HTMLResponse(content=page, status_code=201)


