def soft_delete_attachment_route(reference: str, attachment_id: int, request: Request):
    return _apply_attachment_lifecycle_action(
        reference=reference,
        attachment_id=attachment_id,
        request=request,
        action="soft-delete",
        event_type="attachment_soft_deleted",
        is_deleted=1,
    )
